import { useEffect, useState } from "react";

const SIZE = 10;

function randomFood() {
  return [
    Math.floor(Math.random() * SIZE),
    Math.floor(Math.random() * SIZE),
  ];
}

function progress(game) {
  const [row, col] = game.snake[0];

  const head = [
    row + game.direction[0],
    col + game.direction[1],
  ];

  const snake = [
    head,
    ...game.snake,
  ];

  const ateFood =
    head[0] === game.food[0] &&
    head[1] === game.food[1];

  if (ateFood) {
    return {
      ...game,
      snake,
      food: randomFood(),
    };
  }

  snake.pop();

  return {
    ...game,
    snake,
  };
}

export default function Snake() {
  const [game, setGame] = useState({
    snake: [[5, 5]],
    food: [2, 2],
    direction: [0, 1],
  });

  useEffect(() => {
    const timer = setInterval(() => {
      setGame(progress);
    }, 300);

    return () => clearInterval(timer);
  }, []);

  function keyDown(e) {
    if (e.key === "ArrowUp") {
      setGame(g => ({ ...g, direction: [-1, 0] }));
    }

    if (e.key === "ArrowDown") {
      setGame(g => ({ ...g, direction: [1, 0] }));
    }

    if (e.key === "ArrowLeft") {
      setGame(g => ({ ...g, direction: [0, -1] }));
    }

    if (e.key === "ArrowRight") {
      setGame(g => ({ ...g, direction: [0, 1] }));
    }
  }

  function cell(row, col) {
    if (
      game.snake.some(([r, c]) => r === row && c === col)
    ) {
      return "green";
    }

    if (
      game.food[0] === row &&
      game.food[1] === col
    ) {
      return "red";
    }

    return "white";
  }

  return (
    <main onKeyDown={keyDown} tabIndex={0}>
      <h1>🐍 Snake</h1>

      <table>
        <tbody>
          {Array.from({ length: SIZE }, (_, row) => (
            <tr key={row}>
              {Array.from({ length: SIZE }, (_, col) => (
                <td
                  key={col}
                  style={{
                    width: 25,
                    height: 25,
                    border: "1px solid",
                    background: cell(row, col),
                  }}
                />
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
